import { BLANK_CLUSTER, PRODUCT_NAME } from './constants';

export function init($plugin, store) {
  const { product, basicType } = $plugin.DSL(store, PRODUCT_NAME);

  product({
    icon: 'pod',
    inStore: 'cluster',
    removable: false,
    weight: 100,
    to: {
      name: `${ PRODUCT_NAME }-c-cluster-overview`,
      path: `/${ PRODUCT_NAME }/c/:cluster/overview`,
      params: {
        product: PRODUCT_NAME,
        cluster: BLANK_CLUSTER,
        pkg: PRODUCT_NAME,
      },
    },
  });

  basicType([
    'overview',
    'history',
  ]);
}

export default init;
